#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
const int N=3010,Mod=998244353;
inline void DN(int &x){x>=Mod?x-=Mod:0;}
inline void UP(int &x){x<0?x+=Mod:0;}
vector<int> G[N];int dp[N][N],n;
inline int dfs(int u,int i,int fa=0)
{
	if(~dp[u][i])return dp[u][i];
	if(G[u].size()==1&&fa)return i;
	int &ans=dp[u][i]=1;
	for(int v:G[u])if(v!=fa)ans=1ll*ans*dfs(v,i+1,u)%Mod;
	if(i>1)DN(ans+=dfs(u,i-1,fa));return ans;
}
int main()
{
	scanf("%d",&n);rep(2,n,i)
	{
		int x,y;
		scanf("%d%d",&x,&y);
		G[x].push_back(y);
		G[y].push_back(x);
	}
	memset(dp,-1,sizeof(dp));
	printf("%d\n",dfs(n,0));
}
